#!/usr/bin/env node
/**
 * Bundles bitbox-api WASM + JS glue into a single HTML file
 * that can be loaded in a React Native WebView.
 *
 * Usage: node scripts/bundle-bitbox-wasm.js
 * Output: src/services/hardware-wallet/bitbox-wasm-html.ts
 */

const fs = require('fs');
const path = require('path');

const BITBOX_PKG = path.join(__dirname, '..', 'node_modules', 'bitbox-api');
const OUTPUT = path.join(__dirname, '..', 'src', 'services', 'hardware-wallet', 'bitbox-wasm-html.ts');

// Read WASM binary and JS glue
const wasmBinary = fs.readFileSync(path.join(BITBOX_PKG, 'bitbox_api_bg.wasm'));
const jsGlue = fs.readFileSync(path.join(BITBOX_PKG, 'bitbox_api_bg.js'), 'utf-8');

const wasmBase64 = wasmBinary.toString('base64');

console.log(`WASM size: ${wasmBinary.length} bytes (${wasmBase64.length} base64)`);
console.log(`JS glue size: ${jsGlue.length} chars`);

// Patch the JS glue to work in a WebView context:
// 1. Remove import.meta references (not available in inline scripts)
// 2. Remove any Node.js-specific code
let patchedGlue = jsGlue
  // Remove export statements (we'll access everything via the wasm object)
  .replace(/^export\s+/gm, '')
  // Fix TextEncoder/TextDecoder (available in WebView)
  .replace(/require\(['"]util['"]\)/g, '{}');

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
</head>
<body>
<script>
// ============================================================
// BitBox02 WASM Bridge for React Native
// Generated by scripts/bundle-bitbox-wasm.js
// ============================================================

(async function() {
  'use strict';

  // --- Load WASM from base64 ---
  const wasmBase64 = '${wasmBase64}';
  const wasmBytes = Uint8Array.from(atob(wasmBase64), c => c.charCodeAt(0));

  // --- Initialize WASM module ---
  let wasm;
  try {
    const wasmModule = await WebAssembly.instantiate(wasmBytes, {
      // The JS glue provides import functions via __wbg_* bindings
      // We'll set them up after loading the glue code
    });
    // Note: Full initialization happens through the glue code below
  } catch(e) {
    window.ReactNativeWebView.postMessage(JSON.stringify({
      type: 'error', error: 'WASM init failed: ' + e.message
    }));
    return;
  }

  // --- Transport Bridge ---
  // Bridges USB/BLE transport from React Native to WASM
  let pendingReads = [];

  const transport = {
    write: function(data) {
      return new Promise(function(resolve) {
        window.ReactNativeWebView.postMessage(JSON.stringify({
          type: 'transport_write',
          data: Array.from(data)
        }));
        resolve(data.length);
      });
    },
    read: function() {
      return new Promise(function(resolve) {
        pendingReads.push(resolve);
        window.ReactNativeWebView.postMessage(JSON.stringify({
          type: 'transport_read'
        }));
      });
    }
  };

  // --- Noise Pairing Persistence ---
  // Store pairing data in localStorage (persists in WebView)
  const pairingStore = {
    get: function(key) { return localStorage.getItem('bb_' + key); },
    set: function(key, val) { localStorage.setItem('bb_' + key, val); },
    del: function(key) { localStorage.removeItem('bb_' + key); }
  };

  // --- State ---
  let pairedBitBox = null;

  // --- RPC Handler ---
  async function handleRPC(msg) {
    const { id, method, params } = msg;
    try {
      let result;
      switch(method) {
        case 'ping':
          result = 'pong';
          break;

        case 'pair':
          // Full pairing flow would go here
          // For now, signal that we're ready
          result = { status: 'ready' };
          break;

        case 'deviceInfo':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.deviceInfo();
          break;

        case 'product':
          if (!pairedBitBox) throw new Error('Not paired');
          result = pairedBitBox.product();
          break;

        case 'ethAddress':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.ethAddress(
            BigInt(params[0]), // chainId
            params[1],        // keypath
            params[2]         // display
          );
          break;

        case 'ethXpub':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.ethXpub(params[0]);
          break;

        case 'ethSign1559Transaction':
          if (!pairedBitBox) throw new Error('Not paired');
          var sig = await pairedBitBox.ethSign1559Transaction(
            params[0], // keypath
            params[1], // tx
            params[2]  // address_case
          );
          result = {
            r: Array.from(sig.r),
            s: Array.from(sig.s),
            v: Array.from(sig.v)
          };
          break;

        case 'ethSignMessage':
          if (!pairedBitBox) throw new Error('Not paired');
          var msgSig = await pairedBitBox.ethSignMessage(
            BigInt(params[0]), // chainId
            params[1],         // keypath
            new Uint8Array(params[2]) // msg bytes
          );
          result = {
            r: Array.from(msgSig.r),
            s: Array.from(msgSig.s),
            v: Array.from(msgSig.v)
          };
          break;

        case 'ethSignTypedMessage':
          if (!pairedBitBox) throw new Error('Not paired');
          var typedSig = await pairedBitBox.ethSignTypedMessage(
            BigInt(params[0]), // chainId
            params[1],         // keypath
            params[2]          // msg (JSON)
          );
          result = {
            r: Array.from(typedSig.r),
            s: Array.from(typedSig.s),
            v: Array.from(typedSig.v)
          };
          break;

        case 'btcAddress':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.btcAddress(
            params[0], // coin
            params[1], // keypath
            params[2], // scriptConfig
            params[3]  // display
          );
          break;

        case 'btcXpub':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.btcXpub(
            params[0], // coin
            params[1], // keypath
            params[2], // xpubType
            params[3]  // display
          );
          break;

        case 'btcSignPSBT':
          if (!pairedBitBox) throw new Error('Not paired');
          result = await pairedBitBox.btcSignPSBT(
            params[0], // coin
            params[1], // psbt
            params[2], // force_script_config
            params[3]  // format_unit
          );
          break;

        case 'close':
          if (pairedBitBox) {
            pairedBitBox.close();
            pairedBitBox = null;
          }
          result = true;
          break;

        default:
          throw new Error('Unknown method: ' + method);
      }

      window.ReactNativeWebView.postMessage(JSON.stringify({ id: id, result: result }));
    } catch(err) {
      window.ReactNativeWebView.postMessage(JSON.stringify({
        id: id,
        error: err.message || String(err)
      }));
    }
  }

  // --- Message handler from React Native ---
  document.addEventListener('message', function(event) {
    try {
      var msg = JSON.parse(event.data);

      if (msg.type === 'transport_read_response') {
        if (pendingReads.length > 0) {
          var resolve = pendingReads.shift();
          resolve(new Uint8Array(msg.data));
        }
        return;
      }

      if (msg.id !== undefined && msg.method) {
        handleRPC(msg);
        return;
      }
    } catch(e) {
      // Ignore malformed messages
    }
  });

  // Also listen on window (some RN WebView versions use this)
  window.addEventListener('message', function(event) {
    document.dispatchEvent(new MessageEvent('message', { data: event.data }));
  });

  // Signal ready
  window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'ready' }));

})();
</script>
</body>
</html>`;

// Write as TypeScript module
const output = `// Auto-generated by scripts/bundle-bitbox-wasm.js — DO NOT EDIT
// Contains bitbox-api WASM (${wasmBinary.length} bytes) + JS glue (${jsGlue.length} bytes)
// Re-generate with: node scripts/bundle-bitbox-wasm.js

export const BITBOX_WASM_HTML = ${JSON.stringify(html)};
`;

fs.writeFileSync(OUTPUT, output);
console.log(`Written to ${OUTPUT} (${output.length} chars)`);
